import { type MouseEvent as ReactMouseEvent } from 'react';

import {
  useSetTooltipState,
  useTooltipPinnedStatus,
} from './use-set-tooltip-state.js';
import type { GanttSegmentData } from '../types/gantt-chart.js';

/**
 * Hook that generates handlers for mouse interactions.
 *
 * @param content - The gantt segment content data object.
 * @returns Handlers to perform mouse interactions.
 */
export function useGanttEntryHandlers(content?: {
  segment: GanttSegmentData;
  row: GanttSegmentData[];
  parent?: GanttSegmentData[];
}) {
  const isTooltipPinned = useTooltipPinnedStatus();
  const {
    setTooltipStateContent,
    setTooltipStatePinned,
    setTooltipStateVisibility,
    setTooltipStatePosition,
  } = useSetTooltipState();

  if (content === undefined) {
    return {
      onMouseEnterHandler: undefined,
      onMouseClickHandler: undefined,
      onMouseLeaveHandler: undefined,
    };
  }

  const onMouseEnterHandler = () => {
    setTooltipStateVisibility(true);
    setTooltipStateContent({
      segment: content.segment,
      row: content.row,
      parent: content.parent,
    });
  };

  const onMouseMoveHandler = (event: ReactMouseEvent<SVGElement>) => {
    const { clientX, clientY } = event;

    const position = {
      x: clientX,
      y: clientY,
    };

    setTooltipStatePosition(position);
  };

  const onMouseClickHandler = () => {
    // Temporarily unpin tooltip to force re-render with updated content
    setTooltipStatePinned(false);
    setTooltipStateContent({
      segment: content.segment,
      row: content.row,
      parent: content.parent,
    });
    // Re-pin in next frame to avoid timing issues
    requestAnimationFrame(() => setTooltipStatePinned(true));
  };

  const onMouseLeaveHandler = () => {
    !isTooltipPinned && setTooltipStateVisibility(false);
    setTooltipStateContent(undefined);
  };

  return {
    onMouseEnterHandler,
    onMouseClickHandler,
    onMouseLeaveHandler,
    onMouseMoveHandler,
  };
}
